diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index c1ce364eb179..a19070c7d176 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -1000,6 +1000,39 @@ Instruction *InstCombinerImpl::foldAddWithConstant(BinaryOperator &Add) {
         Add, Builder.CreateBinaryIntrinsic(
                  Intrinsic::usub_sat, X, ConstantInt::get(Add.getType(), -*C)));

+  // Fold ceiling division pattern:
+  // add (lshr X, C), (zext (icmp ne (and X, (2^C-1)), 0))
+  //   -> lshr (add X, (2^C-1)), C
+  // This is equivalent to: (X / 2^C) + (X % 2^C != 0 ? 1 : 0) -> (X + 2^C - 1) / 2^C
+  {
+    Value *X;
+    const APInt *ShAmt;
+    CmpPredicate Pred;
+    // Match: add (lshr X, C), (zext (icmp ne (and X, Mask), 0))
+    if (match(Op0, m_LShr(m_Value(X), m_APInt(ShAmt))) &&
+
+        match(Op0, m_OneUse(m_LShr(m_Value(X), m_APInt(ShAmt)))) &&
+        ShAmt->ult(Ty->getScalarSizeInBits())) {
+      unsigned ShAmtC = ShAmt->getZExtValue();
+      APInt Mask = APInt::getLowBitsSet(Ty->getScalarSizeInBits(), ShAmtC);
+      // Match: zext (icmp ne (and X, Mask), 0)
+      const APInt *AndC;
+      if (match(&Add,
+                m_c_Add(m_Specific(Op0),
+                        m_OneUse(m_ZExt(m_OneUse(m_ICmp(
+                            Pred, m_OneUse(m_And(m_Specific(X), m_APInt(AndC))),
+                            m_Zero()))))))) {
+        if (*AndC == Mask && Pred == ICmpInst::ICMP_NE) {
+          // Create: lshr (add X, (2^C-1)), C
+          Value *NewAdd = Builder.CreateAdd(
+              X, ConstantInt::get(Ty, Mask), "",
+              /*HasNUW=*/true, /*HasNSW=*/false);
+          return BinaryOperator::CreateLShr(NewAdd, ConstantInt::get(Ty, ShAmtC));
+        }
+      }
+    }
+  }
+
   // Fold (add (zext (add X, -1)), 1) -> (zext X) if X is non-zero.
   // TODO: There's a general form for any constant on the outer add.
   if (C->isOne()) {
@@ -1784,6 +1817,40 @@ Instruction *InstCombinerImpl::visitAdd(BinaryOperator &I) {
     return replaceInstUsesWith(I, UMax);
   }

+  // Fold ceiling division pattern:
+  // add (lshr X, C), (zext (icmp ne (and X, (2^C-1)), 0))
+  //   -> lshr (add X, (2^C-1)), C
+  // This is equivalent to: (X / 2^C) + (X % 2^C != 0 ? 1 : 0) -> (X + 2^C - 1) / 2^C
+  {
+    Value *X;
+    const APInt *ShAmt;
+    CmpPredicate Pred;
+    // Match: add (lshr X, C), (zext (icmp ne (and X, Mask), 0))
+    if (match(LHS, m_OneUse(m_LShr(m_Value(X), m_APInt(ShAmt)))) &&
+        ShAmt->ult(Ty->getScalarSizeInBits())) {
+      unsigned ShAmtC = ShAmt->getZExtValue();
+      APInt Mask = APInt::getLowBitsSet(Ty->getScalarSizeInBits(), ShAmtC);
+      // Match: zext (icmp ne (and X, Mask), 0)
+      const APInt *AndC;
+      if (match(RHS, m_OneUse(m_ZExt(m_OneUse(m_ICmp(
+              Pred, m_OneUse(m_And(m_Specific(X), m_APInt(AndC))), m_Zero())))))) {
+        if (*AndC == Mask && Pred == ICmpInst::ICMP_NE) {
+          // Check that X + Mask won't overflow
+          WithCache<const Value *> XCache(X);
+          ConstantInt *MaskVal = cast<ConstantInt>(ConstantInt::get(Ty, Mask));
+          WithCache<const Value *> MaskCache(MaskVal);
+          if (!willNotOverflowUnsignedAdd(XCache, MaskCache, I))
+            return nullptr;
+          // Create: lshr (add X, (2^C-1)), C
+          Value *NewAdd = Builder.CreateAdd(
+              X, MaskVal, "",
+              /*HasNUW=*/true, /*HasNSW=*/false);
+          return BinaryOperator::CreateLShr(NewAdd, ConstantInt::get(Ty, ShAmtC));
+        }
+      }
+    }
+  }
+
   if (Instruction *Ashr = foldAddToAshr(I))
     return Ashr;

